class KoD3XSearch{constructor(){this.init()}init(){document.querySelectorAll("[kod3x-search-input]").forEach((e=>{const t=e.getAttribute("kod3x-search-input");e.addEventListener("input",(()=>{this.filterItems(t,e.value.trim().toLowerCase())})),this.filterItems(t,"")}))}filterItems(e,t){const s=document.querySelectorAll(`[kod3x-search="${e}"]`),o=document.getElementById("no-results");let d=0;s.forEach((e=>{const s=e.textContent.toLowerCase().includes(t);""===t||s?(e.classList.remove("kod3x-search-hidden","kod3x-search-completely-hidden"),d++):(e.classList.add("kod3x-search-hidden"),setTimeout((()=>{e.classList.contains("kod3x-search-hidden")&&e.classList.add("kod3x-search-completely-hidden")}),300))})),o&&(o.style.display=0===d&&""!==t?"block":"none")}}document.addEventListener("DOMContentLoaded",(()=>{window.KoD3XSearch=new KoD3XSearch}));